mapper.select:
SELECT DISTINCT small_category AS value
FROM new_category
WHERE large_category = #{largeCategory}
AND medium_category = #{mediumCategory}
ORDER BY small_category

SELECT COUNT(*)
FROM new_category
WHERE large_category = #{largeCategory}
AND medium_category = #{mediumCategory}
AND small_category = #{smallCategory}

SELECT COUNT(*)
FROM new_category
WHERE id != #{id}
AND large_category = #{largeCategory}
AND medium_category = #{mediumCategory}
AND small_category = #{smallCategory}

SELECT id
FROM new_category
WHERE large_category = #{largeCategory}
AND medium_category = #{mediumCategory}
AND small_category = #{smallCategory}
LIMIT 1

mapper.update:
UPDATE new_category
SET large_category = #{largeCategory},
medium_category = #{mediumCategory},
small_category = #{smallCategory}
WHERE id = #{id}
